  }) {
    final timestamp = DateTime.now().toIso8601String();
    String logMessage = '[$timestamp][${level.name}][$tag] $message';

    if (payload != null) {
      try {
        logMessage += '\nPayload: ${jsonEncode(payload)}';
      } catch (e) {
        logMessage += '\nPayload: $payload (Non-serializable)';
