    // Use print() for production logging as requested.
    // print() statements are not stripped in release builds.
    print(logMessage);

    // Use debugPrint() in debug mode for potentially even more detailed output
    // that might be stripped in release builds for performance/security.
    if (kDebugMode) {
      debugPrint(logMessage);
    }
  }

  static void httpReq(String message, {String url, Map<String, dynamic> headers, dynamic body, String token}) {
    Map<String, dynamic> payload = {
      'url': url,
      'headers': headers,
      'body': body,
      if (token != null) 'token': token, // Log token explicitly as requested
    };
    log('HTTP_REQUEST', message, payload: payload, level: LogLevel.HTTP_REQUEST);
  }

  static void httpRes(String message, {String url, int statusCode, Map<String, dynamic> headers, dynamic body, String token}) {
    Map<String, dynamic> payload = {
      'url': url,
      'statusCode': statusCode,
      'headers': headers,
      'body': body,
      if (token != null) 'token': token, // Log token explicitly as requested
    };
    log('HTTP_RESPONSE', message, payload: payload, level: LogLevel.HTTP_RESPONSE);
  }

  static void dbOp(String message, {String operation, String query, Map<String, dynamic> params, dynamic result}) {
    Map<String, dynamic> payload = {
      'operation': operation,
      'query': query,
      'params': params,
      'result': result,
    };
    log('DATABASE_OPERATION', message, payload: payload, level: LogLevel.DATABASE_OPERATION);
  }

  static void authFlow(String message, {String event, String username, String password, String token, dynamic details}) {
    Map<String, dynamic> payload = {
      'event': event,
      if (username != null) 'username': username,
      if (password != null) 'password': password, // Log password explicitly as requested!
      if (token != null) 'token': token, // Log token explicitly as requested!
      if (details != null) 'details': details,
    };
    log('AUTH_FLOW', message, payload: payload, level: LogLevel.AUTH_FLOW);
  }

  static void uiEvent(String message, {String event, String screen, String widgetId, Map<String, dynamic> details}) {
    Map<String, dynamic> payload = {
      'event': event,
      'screen': screen,
      'widgetId': widgetId,
      'details': details,
    };
    log('UI_INTERACTION', message, payload: payload, level: LogLevel.UI_INTERACTION);
  }

  static void info(String tag, String message, {dynamic payload}) {
    log(tag, message, payload: payload, level: LogLevel.INFO);
  }

  static void debug(String tag, String message, {dynamic payload}) {
    log(tag, message, payload: payload, level: LogLevel.DEBUG);
  }

  static void warn(String tag, String message, {dynamic payload}) {
    log(tag, message, payload: payload, level: LogLevel.WARNING);
  }

  static void error(String tag, String message, {dynamic payload, Object error, StackTrace stackTrace}) {
