// lib/http_logging_interceptor.dart
import 'package:dio/dio.dart';
import 'package:flutter_app_logging_system/app_logger.dart';

class HttpLoggingInterceptor extends Interceptor {
  @override
  void onRequest(RequestOptions options, RequestInterceptorHandler handler) {
    AppLogger.httpReq(
      'Sending HTTP Request',
      url: options.uri.toString(),
      headers: options.headers,
      body: options.data,
      token: options.headers['Authorization'], // Extract token from headers
    );
    super.onRequest(options, handler);
  }

  @override
  void onResponse(Response response, ResponseInterceptorHandler handler) {
    AppLogger.httpRes(
      'Received HTTP Response',
      url: response.requestOptions.uri.toString(),
      statusCode: response.statusCode,
      headers: response.headers.map,
      body: response.data,
      token: response.requestOptions.headers['Authorization'], // Extract token from request headers for context
    );
    super.onResponse(response, handler);
  }

  @override
  void onError(DioException err, ErrorInterceptorHandler handler) {
    AppLogger.error(
      'HTTP_ERROR',
      'HTTP Request Failed',
      payload: {
        'url': err.requestOptions.uri.toString(),
        'method': err.requestOptions.method,
        'statusCode': err.response?.statusCode,
        'response_data': err.response?.data,
        'message': err.message,
        'error_type': err.type.name,
      },
      error: err,
      stackTrace: err.stackTrace,
    );
    super.onError(err, handler);
  }
}

// lib/database_service.dart
import 'package:sqflite/sqflite.dart';
import 'package:path/path.dart';
import 'package:flutter_app_logging_system/app_logger.dart';

class DatabaseService {
  static Database _database;

  Future<Database> get database async {
    if (_database != null) return _database;
    _database = await _initDB();
    return _database;
  }

  Future<Database> _initDB() async {
    String path = join(await getDatabasesPath(), 'app_database.db');
    return await openDatabase(
      path,
      version: 1,
      onCreate: (db, version) async {
        await db.execute(
          "CREATE TABLE users(id INTEGER PRIMARY KEY, name TEXT, email TEXT)",
        );
        AppLogger.dbOp('Table "users" created', operation: 'CREATE_TABLE', query: 'CREATE TABLE users(...)');
      },
      onUpgrade: (db, oldVersion, newVersion) {
        AppLogger.dbOp('Database upgraded', operation: 'UPGRADE', query: 'old:$oldVersion, new:$newVersion');
      }
    );
  }

  Future<int> insertUser(Map<String, dynamic> user) async {
    final db = await database;
    int id = await db.insert('users', user);
    AppLogger.dbOp('User inserted', operation: 'INSERT', query: 'INSERT INTO users', params: user, result: id);
    return id;
  }

  Future<List<Map<String, dynamic>>> getUsers() async {
    final db = await database;
    List<Map<String, dynamic>> users = await db.query('users');
    AppLogger.dbOp('Users queried', operation: 'SELECT', query: 'SELECT * FROM users', result: users);
    return users;
  }

  Future<int> updateUser(int id, Map<String, dynamic> user) async {
    final db = await database;
    int rowsAffected = await db.update('users', user, where: 'id = ?', whereArgs: [id]);
    AppLogger.dbOp('User updated', operation: 'UPDATE', query: 'UPDATE users WHERE id = ?', params: {'id': id, 'data': user}, result: rowsAffected);
    return rowsAffected;
  }

  Future<int> deleteUser(int id) async {
    final db = await database;
    int rowsAffected = await db.delete('users', where: 'id = ?', whereArgs: [id]);
    AppLogger.dbOp('User deleted', operation: 'DELETE', query: 'DELETE FROM users WHERE id = ?', params: {'id': id}, result: rowsAffected);
    return rowsAffected;
  }
}

// lib/auth_service.dart
import 'package:flutter_app_logging_system/app_logger.dart';

class AuthService {
  String _currentToken;

  Future<bool> login(String username, String password) async {
    // Simulate API call
    await Future.delayed(Duration(seconds: 2));

    if (username == 'user' && password == 'pass') {
      _currentToken = 'mock_jwt_token_12345';
      AppLogger.authFlow(
        'User logged in successfully',
        event: 'LOGIN_SUCCESS',
        username: username,
        password: password, // Logging password as requested!
        token: _currentToken,
      );
      return true;
    } else {
      AppLogger.authFlow(
        'Login failed',
        event: 'LOGIN_FAILURE',
        username: username,
        password: password, // Logging password as requested!
        details: 'Invalid credentials',
      );
      return false;
    }
  }

  Future<bool> register(String username, String password, String email) async {
    // Simulate API call
    await Future.delayed(Duration(seconds: 2));

    if (username.isNotEmpty && password.isNotEmpty && email.isNotEmpty) {
      AppLogger.authFlow(
        'User registered successfully',
        event: 'REGISTER_SUCCESS',
        username: username,
        password: password, // Logging password as requested!
        details: {'email': email},
      );
      return true;
    } else {
      AppLogger.authFlow(
        'Registration failed',
        event: 'REGISTER_FAILURE',
        username: username,
        password: password, // Logging password as requested!
        details: 'Missing information',
      );
      return false;
    }
  }

  Future<void> logout() async {
    AppLogger.authFlow(
      'User logged out',
      event: 'LOGOUT',
      username: 'current_user_id', // Add actual user ID if available
      token: _currentToken,
    );
    _currentToken = null;
  }

  String getCurrentToken() => _currentToken;
}

// lib/main.dart
import 'package:flutter/material.dart';
import 'package:dio/dio.dart';
import 'package:flutter_app_logging_system/app_logger.dart';
import 'package:flutter_app_logging_system/http_logging_interceptor.dart';
import 'package:flutter_app_logging_system/database_service.dart';
import 'package:flutter_app_logging_system/auth_service.dart';

void main() {
  // Initialize Dio with the logging interceptor
  final Dio dio = Dio();
  dio.interceptors.add(HttpLoggingInterceptor());

  // Initialize services
  final DatabaseService dbService = DatabaseService();
  final AuthService authService = AuthService();

  runApp(MyApp(
    dio: dio,
    dbService: dbService,
    authService: authService,
  ));
}

class MyApp extends StatelessWidget {
  final Dio dio;
  final DatabaseService dbService;
  final AuthService authService;

  MyApp({this.dio, this.dbService, this.authService});

  @override
  Widget build(BuildContext context) {
    AppLogger.uiEvent('App Started', event: 'APP_START', screen: 'Splash');
    return MaterialApp(
      title: 'Flutter Logging Demo',
      home: MyHomePage(
        dio: dio,
        dbService: dbService,
        authService: authService,
      ),
    );
  }
}

class MyHomePage extends StatefulWidget {
  final Dio dio;
  final DatabaseService dbService;
  final AuthService authService;

  MyHomePage({this.dio, this.dbService, this.authService});

  @override
  _MyHomePageState createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  String _authStatus = 'Logged Out';
  List<Map<String, dynamic>> _users = [];

  @override
  void initState() {
    super.initState();
    _loadUsers();
  }

  Future<void> _loadUsers() async {
    _users = await widget.dbService.getUsers();
    setState(() {});
  }

  Future<void> _performLogin() async {
    AppLogger.uiEvent('Login Button Tapped', event: 'BUTTON_TAP', screen: 'LoginScreen', widgetId: 'login_button');
    bool success = await widget.authService.login('user', 'pass');
    setState(() {
      _authStatus = success ? 'Logged In' : 'Login Failed';
    });
    if (success) {
      AppLogger.info('MAIN_APP', 'Current token: ${widget.authService.getCurrentToken()}');
    }
  }

  Future<void> _performRegistration() async {
    AppLogger.uiEvent('Register Button Tapped', event: 'BUTTON_TAP', screen: 'RegisterScreen', widgetId: 'register_button');
    bool success = await widget.authService.register('newUser', 'newPass123', 'newuser@example.com');
    setState(() {
      _authStatus = success ? 'Registered' : 'Registration Failed';
    });
  }

  Future<void> _performLogout() async {
    AppLogger.uiEvent('Logout Button Tapped', event: 'BUTTON_TAP', screen: 'HomeScreen', widgetId: 'logout_button');
    await widget.authService.logout();
    setState(() {
      _authStatus = 'Logged Out';
    });
  }

  Future<void> _fetchData() async {
    AppLogger.uiEvent('Fetch Data Button Tapped', event: 'BUTTON_TAP', screen: 'HomeScreen', widgetId: 'fetch_data_button');
    try {
      final response = await widget.dio.get('https://jsonplaceholder.typicode.com/posts/1');
      AppLogger.info('MAIN_APP', 'Data fetched successfully', payload: response.data);
    } catch (e, st) {
      AppLogger.error('MAIN_APP', 'Failed to fetch data', error: e, stackTrace: st);
    }
  }

  Future<void> _addDbUser() async {
    AppLogger.uiEvent('Add DB User Button Tapped', event: 'BUTTON_TAP', screen: 'HomeScreen', widgetId: 'add_db_user_button');
    await widget.dbService.insertUser({'name': 'Test User', 'email': 'test@example.com'});
    await _loadUsers();
  }

  @override
  Widget build(BuildContext context) {
    AppLogger.uiEvent('MyHomePage build', event: 'SCREEN_VIEW', screen: 'MyHomePage');
    return Scaffold(
      appBar: AppBar(
        title: Text('Logging Demo'),
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: <Widget>[
            Text('Authentication Status: $_authStatus'),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: _performLogin,
              child: Text('Login'),
            ),
            ElevatedButton(
              onPressed: _performRegistration,
              child: Text('Register'),
            ),
            ElevatedButton(
              onPressed: _performLogout,
              child: Text('Logout'),
            ),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: _fetchData,
              child: Text('Fetch External Data (HTTP)'),
            ),
            SizedBox(height: 20),
            Text('Database Users:'),
            ..._users.map((user) => Text('${user['id']}: ${user['name']} (${user['email']})')),
            ElevatedButton(
              onPressed: _addDbUser,
              child: Text('Add DB User'),
            ),
          ],
        ),
      ),
    );
  }
}